// Simulated HR leave data. Looked up by email (query param), case-insensitive.
const email = ($json.query && $json.query.email ? String($json.query.email) : '').toLowerCase().trim();
const db = {
  'staff@tertiaryinfotech.com': { name: 'Alex Tan',  entitlement: 18, annualTaken: 6, medicalTaken: 2 },
  'angch@tertiaryinfotech.com': { name: 'Ang Chew Hoe', entitlement: 18, annualTaken: 3, medicalTaken: 0 },
};
const def = { name: 'Staff Member', entitlement: 14, annualTaken: 4, medicalTaken: 1 };
const r = db[email] || def;
const annualBalance = r.entitlement - r.annualTaken;
const medicalEntitlement = 14;
return [{ json: {
  name: r.name,
  email: email || 'staff@tertiaryinfotech.com',
  annual:  { entitlement: r.entitlement, taken: r.annualTaken, balance: annualBalance },
  medical: { entitlement: medicalEntitlement, taken: r.medicalTaken, balance: medicalEntitlement - r.medicalTaken },
  recent: [
    { type: 'Annual',  dates: '2026-05-12 → 2026-05-13', days: 2, status: 'Approved' },
    { type: 'Medical', dates: '2026-04-02',               days: 1, status: 'Approved' },
    { type: 'Annual',  dates: '2026-06-30 → 2026-07-01', days: 2, status: 'Pending'  },
  ],
} }];
